const { Kafka } = require('kafkajs');

// Simple consumer that reads a partition and pushes to a gateway socket
const kafka = new Kafka({ clientId: 'gateway-consumer', brokers: ['kafka1:9092'] });
const consumer = kafka.consumer({ groupId: 'gateway-shard-42' });

async function run() {
  await consumer.connect();
  await consumer.subscribe({ topic: 'events-by-guild', fromBeginning: false });

  await consumer.run({
    eachMessage: async ({ topic, partition, message }) => {
      const payload = JSON.parse(message.value.toString());
      // idempotency check (very small in‑memory window)
      if (seen(payload.id)) return;
      // push to clients connected to this gateway
      pushToClients(payload);
      markSeen(payload.id);
    }
  });
}

run().catch(console.error);
